INSERT INTO `v1_f386483c38d65cda4c53d79dd01b9f40ac7715a892e274b8120bb0b5b8efa1f0` VALUES ("", 10, "", "", "うわぁ～…！\n大きくなりすぎて\nやばいですね☆", 1, 105831, 11, "", "", 1010020);
INSERT INTO `v1_f386483c38d65cda4c53d79dd01b9f40ac7715a892e274b8120bb0b5b8efa1f0` VALUES ("", "", "", "", "", 1, 0, 91, "", "", 1010021);
INSERT INTO `v1_f386483c38d65cda4c53d79dd01b9f40ac7715a892e274b8120bb0b5b8efa1f0` VALUES ("", 10, "", "", "うえきちゃんが\nどこまで続くのか\n分からないほどです", 1, 105931, 11, "", "", 1010022);
INSERT INTO `v1_f386483c38d65cda4c53d79dd01b9f40ac7715a892e274b8120bb0b5b8efa1f0` VALUES ("", "", "", "", "", 1, 0, 91, "", "", 1010023);
INSERT INTO `v1_f386483c38d65cda4c53d79dd01b9f40ac7715a892e274b8120bb0b5b8efa1f0` VALUES ("", 10, "", "", "こういうのってさ\n上がどうなってるか\n見てみたいよね！", 1, 112631, 11, "", "", 1010024);
INSERT INTO `v1_f386483c38d65cda4c53d79dd01b9f40ac7715a892e274b8120bb0b5b8efa1f0` VALUES ("", "", "", "", "", 1, 0, 91, "", "", 1010025);
INSERT INTO `v1_f386483c38d65cda4c53d79dd01b9f40ac7715a892e274b8120bb0b5b8efa1f0` VALUES ("", 10, "", "", "確かにね…それに\nこうなった理由も\n分かるかも", 1, 112531, 11, "", "", 1010026);
INSERT INTO `v1_f386483c38d65cda4c53d79dd01b9f40ac7715a892e274b8120bb0b5b8efa1f0` VALUES ("", "", "", "", "", 1, 0, 91, "", "", 1010027);
INSERT INTO `v1_f386483c38d65cda4c53d79dd01b9f40ac7715a892e274b8120bb0b5b8efa1f0` VALUES ("", 10, "", "", "ま、興味はあるし\n付き合ってあげるわ", 1, 106031, 11, "", "", 1010028);
INSERT INTO `v1_f386483c38d65cda4c53d79dd01b9f40ac7715a892e274b8120bb0b5b8efa1f0` VALUES ("", "", "", "", "", 1, 0, 91, "", "", 1010029);
INSERT INTO `v1_f386483c38d65cda4c53d79dd01b9f40ac7715a892e274b8120bb0b5b8efa1f0` VALUES ("", 10, "", "", "はい♪みなさんで\n頂上を目指して\n頑張りましょう！", 1, 112431, 11, "", "", 1010030);
